// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract EpochManager {
    struct EpochState {
        uint256 timestamp;
        bool finalized;
    }

    // --- NEW CONSTANTS FOR SYNC ---
    uint256 public immutable GENESIS_TIMESTAMP;
    uint256 public immutable EPOCH_DURATION; 

    uint256 public currentEpoch;
    mapping(uint256 => EpochState) public epochHistory;

    event EpochFinalized(uint256 indexed epoch);

    /**
     * @param _genesisTimestamp The exact Unix timestamp when Epoch 0 begins (e.g., 1712841600)
     * @param _epochDuration How long an epoch lasts in seconds (e.g., 86400 for 1 day)
     */
    constructor(uint256 _genesisTimestamp, uint256 _epochDuration) {
        GENESIS_TIMESTAMP = _genesisTimestamp;
        EPOCH_DURATION = _epochDuration;
        
        currentEpoch = 0;
        epochHistory[0] = EpochState({
            timestamp: _genesisTimestamp,
            finalized: true
        });
    }

    function finalizeEpoch() external {

        // 2. Calculate the exact time this specific epoch MUST end
        // Formula: Genesis + (Epoch Number * Duration)
        uint256 epochEndTime = GENESIS_TIMESTAMP + (currentEpoch * EPOCH_DURATION);

        // 3. Robustness check: Ensure the current blockchain time is past the end of this epoch
        require(block.timestamp >= epochEndTime, "Epoch duration has not elapsed yet");

        EpochState storage state = epochHistory[currentEpoch];
        
        // 4. Ensure data was actually proposed/stored for this epoch before finalizing
        // (Assuming your 'propose' logic fills validatorRoot/variablesRoot)
        require(state.timestamp > 0, "Epoch data not proposed");
        require(!state.finalized, "Already finalized");

        // 5. Update State
        state.finalized = true;
        state.timestamp = block.timestamp; // Record actual finalization time
        currentEpoch = currentEpoch+1;

        emit EpochFinalized(currentEpoch+1);
    }

}

